{
  "title": "कॉन्टेक्स्ट विंडो की बुनियादी बातें",
  "group": "आधार",
  "options": [
    {
      "text": "प्रति मिनट अधिकतम अनुरोधों की संख्या"
    },
    {
      "text": "इनपुट और आउटपुट के लिए संयुक्त टोकन सीमा"
    },
    {
      "text": "कॉन्वर्सेशन में संदेशों की संख्या"
    },
    {
      "text": "सत्रों के बीच उपलब्ध मेमोरी"
    }
  ],
  "questionProse": [
    "LLM में \"कॉन्टेक्स्ट विंडो\" से क्या तात्पर्य है?"
  ],
  "explanationProse": [
    "कॉन्टेक्स्ट विंडो वह कुल टोकन संख्या है जो एक मॉडल एक ही कॉल में प्रोसेस कर सकता है — **इनपुट और आउटपुट दोनों मिलकर**। 128K कॉन्टेक्स्ट विंडो का मतलब है कि आपका प्रॉम्प्ट, रीट्रीव किए गए डॉक्यूमेंट्स, कॉन्वर्सेशन हिस्ट्री और मॉडल का रिस्पॉन्स — ये सब 128,000 टोकन की सीमा के अंदर फिट होने चाहिए。\n\n    इसका सत्रों, मेमोरी या रेट लिमिट्स से बिल्कुल कोई लेना-देना नहीं है। जब आप इस लिमिट को पार कर जाते हैं, तो मॉडल या तो टेक्स्ट काट देता है, एरर फेंकता है, या — और बुरा है — बिना चेतावनी के उन टोकन को ड्रॉप कर देता है जिनकी आपको उम्मीद नहीं थी。"
  ]
}
